const raw = $input.first().json;
const body = raw.body || raw;
const alerts = body.alerts || [];

const statusIcon = (state) => {
  if (state === 'firing') return '🔴';
  if (state === 'resolved') return '✅';
  return '⚪';
};

const severityIcon = (severity) => {
  if (severity === 'critical') return '🚨';
  if (severity === 'warning') return '⚠️';
  return 'ℹ️';
};

const messages = alerts.map(alert => {
  const icon = statusIcon(alert.status);
  const sevIcon = severityIcon(alert.labels?.severity);
  const name = alert.labels?.alertname || 'Alerta';
  const summary = alert.annotations?.summary || '';
  const description = alert.annotations?.description || '';
  const instance = alert.labels?.instance || '';
  const gateway = alert.labels?.gateway || '';
  const state = alert.status === 'firing' ? 'DISPARADO' : 'RESOLVIDO';

  let text = `${icon} *pfSense — ${name}*\n`;
  text += `${sevIcon} Status: *${state}*\n`;
  if (summary) text += `📋 ${summary}\n`;
  if (description) text += `📝 ${description}\n`;
  if (gateway) text += `🌐 Gateway: ${gateway}\n`;
  if (instance) text += `🖥️ Host: ${instance}\n`;
  text += `🕐 ${new Date().toLocaleString('pt-BR', {timeZone: 'America/Sao_Paulo'})}`;

  return { text };
});

return messages.map(m => ({ json: m }));
